document.addEventListener("DOMContentLoaded", () => {
  console.log("Website Yh'rez Grafika Berhasil Dimuat.");

  // 1. Smooth Scrolling untuk link navigasi
  document.querySelectorAll('a[href^="#"]').forEach((anchor) => {
    const href = anchor.getAttribute("href");
    if (!href || href === "#") return;

    anchor.addEventListener("click", function (e) {
      const targetId = href.slice(1);
      if (!targetId) return;

      const target = document.getElementById(targetId);
      if (!target) return;

      e.preventDefault();
      window.scrollTo({
        top: target.offsetTop - 80, // Ruang untuk navbar
        behavior: "smooth",
      });
    });
  });

  // 2. Navbar Animation & Scroll Effect
  const nav = document.getElementById("main-nav");
  const waFloat = document.querySelector(".wa-float");
  const NAV_COMPACT_OFFSET = 24;
  const WA_SHOW_DELAY = 1200;
  const WA_HIDE_IDLE_DELAY = 2200;
  let waShowTimer = null;
  let waHideTimer = null;

  let navCompact = false;
  let scrollTicking = false;

  const applyScrollEffects = () => {
    const y = window.scrollY || document.documentElement.scrollTop;
    const shouldCompact = y > NAV_COMPACT_OFFSET;

    if (nav && shouldCompact !== navCompact) {
      navCompact = shouldCompact;
      if (navCompact) {
        nav.classList.add("navbar-scrolled");
      } else {
        nav.classList.remove("navbar-scrolled");
      }
    }

    if (!waFloat) return;

    if (shouldCompact) {
      if (!waFloat.classList.contains("show") && !waShowTimer) {
        waShowTimer = setTimeout(() => {
          waFloat.classList.add("show");
          waShowTimer = null;
        }, WA_SHOW_DELAY);
      }

      if (waHideTimer) clearTimeout(waHideTimer);
      waHideTimer = setTimeout(() => {
        waFloat.classList.remove("show");
      }, WA_HIDE_IDLE_DELAY);
    } else {
      if (waShowTimer) {
        clearTimeout(waShowTimer);
        waShowTimer = null;
      }
      if (waHideTimer) {
        clearTimeout(waHideTimer);
        waHideTimer = null;
      }
      waFloat.classList.remove("show");
    }
  };
  const onScroll = () => {
    if (scrollTicking) return;
    scrollTicking = true;
    requestAnimationFrame(() => {
      applyScrollEffects();
      scrollTicking = false;
    });
  };

  window.addEventListener("scroll", onScroll, { passive: true });
  window.addEventListener("resize", onScroll, { passive: true });
  window.addEventListener("orientationchange", onScroll, { passive: true });
  onScroll();

  // 3. Menu Mobile Toggle
  const menuToggle = document.getElementById("mobile-menu");
  const navLinks = document.querySelector(".nav-links");

  if (menuToggle && navLinks) {
    const syncMenuIcon = (isOpen) => {
      menuToggle.setAttribute("aria-expanded", String(isOpen));
      const icon = menuToggle.querySelector("i");
      if (icon) {
        icon.classList.toggle("fa-bars", !isOpen);
        icon.classList.toggle("fa-times", isOpen);
      }
    };

    const closeMenu = () => {
      navLinks.classList.remove("active");
      syncMenuIcon(false);
    };

    menuToggle.addEventListener("click", function () {
      const isOpen = navLinks.classList.toggle("active");
      syncMenuIcon(isOpen);
    });

    menuToggle.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") return;
      event.preventDefault();
      const isOpen = navLinks.classList.toggle("active");
      syncMenuIcon(isOpen);
    });

    document.querySelectorAll(".nav-links a").forEach((link) => {
      link.addEventListener("click", () => {
        closeMenu();
      });
    });

    syncMenuIcon(false);
  }

  // 4. Reveal Animation Menggunakan Intersection Observer (lebih ringan)
  const revealElements = document.querySelectorAll(".catalog-card, .product-card, .testimonial-card, .portfolio-item");
  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  if (prefersReducedMotion || !("IntersectionObserver" in window)) {
    revealElements.forEach((el) => {
      el.style.opacity = "1";
      el.style.transform = "none";
      el.style.transition = "none";
    });
  } else {
    const revealThreshold = window.matchMedia("(max-width: 768px)").matches ? 0.1 : 0.15;
    const revealObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("active", "show");
            entry.target.style.opacity = "1";
            entry.target.style.transform = "translateY(0)";
            revealObserver.unobserve(entry.target);
          }
        });
      },
      {
        threshold: revealThreshold,
        rootMargin: "0px 0px -8% 0px",
      },
    );

    revealElements.forEach((el) => {
      el.style.opacity = "0";
      el.style.transform = "translateY(24px)";
      el.style.transition = "opacity 0.55s ease-out, transform 0.55s ease-out";
      revealObserver.observe(el);
    });
  }

  // 5. Filter Kategori Produk
  const filterContainer = document.querySelector(".filter-buttons");
  const productCards = document.querySelectorAll(".product-card");

  if (productCards.length && filterContainer) {
    filterContainer.addEventListener("click", (event) => {
      const btn = event.target.closest(".filter-btn");
      if (!btn) return;

      filterContainer.querySelectorAll(".filter-btn").forEach((b) => b.classList.remove("active"));
      btn.classList.add("active");

      const filter = btn.getAttribute("data-filter") || "all";
      productCards.forEach((card) => {
        const category = card.getAttribute("data-category");
        const shouldShow = filter === "all" || category === filter;
        card.style.display = shouldShow ? "block" : "none";
      });
    });
  }

  // 6. Tombol WhatsApp Order Produk
  const waButtons = document.querySelectorAll(".btn-wa");
  const phoneNumber = "6281348520154";

  waButtons.forEach((btn) => {
    btn.addEventListener("click", (event) => {
      event.preventDefault();
      const directHref = btn.getAttribute("href");
      if (directHref && directHref !== "#") {
        window.open(directHref, "_blank", "noopener,noreferrer");
        return;
      }
      const card = btn.closest(".product-card");
      const productName = btn.getAttribute("data-product") || card?.querySelector("h3")?.textContent?.trim();
      const customMessage = btn.getAttribute("data-message");
      const message = customMessage || (productName ? `Halo, saya ingin pesan ${productName} di Yh'rez Grafika.` : "");
      if (message) {
        window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, "_blank", "noopener,noreferrer");
      }
    });
  });

  // 7. Auto-Slider Profil (Tentang Kami)
  const slides = document.querySelectorAll(".about-slide");
  if (slides.length > 1) {
    let currentSlide = 0;
    setInterval(() => {
      slides[currentSlide].classList.remove("active");
      currentSlide = (currentSlide + 1) % slides.length;
      slides[currentSlide].classList.add("active");
    }, 3000); // Ganti gambar setiap 5 detik
  }

  // 8. Image Modal (Preview Portfolio)
  const modal = document.getElementById("imageModal");
  const modalImg = document.getElementById("modalImage");
  const closeBtn = document.querySelector(".close-modal");
  const images = document.querySelectorAll(".print-portfolio-card img, .portfolio-item img");

  if (modal && modalImg) {
    images.forEach((img) => {
      img.addEventListener("click", () => {
        modal.style.display = "block";
        modalImg.src = img.src;
      });
    });

    if (closeBtn) {
      closeBtn.addEventListener("click", () => (modal.style.display = "none"));
    }

    modal.addEventListener("click", (e) => {
      if (e.target === modal) modal.style.display = "none";
    });
  }

  // 9. Update Jam & Tanggal Hari Ini
  const hariEl = document.getElementById("tanggal-hari");
  if (hariEl) {
    const formattedDate = new Intl.DateTimeFormat("id-ID", {
      weekday: "long",
      day: "numeric",
      month: "long",
      year: "numeric",
    }).format(new Date());

    requestAnimationFrame(() => {
      hariEl.textContent = formattedDate;
    });
  }
});
